import React, { forwardRef, useEffect, useRef, useState } from "react";
import { motion, useTransform } from "framer-motion";
import { CardsTwoProps, CardsTwoRef, Card } from "./types";
import { useCylinder } from "./hooks/useCylinder";
import { useRotation } from "./hooks/useRotation";
import { useCardTransforms } from "./hooks/useCardTransforms";
import { useCardsTwoRef } from "./hooks/useCardsTwo";
import { cn } from "../../lib/utils";

export const CardsTwo = forwardRef<CardsTwoRef, CardsTwoProps>(
  (
    {
      cards,
      radius = 500,
      gap = 40,
      cardWidth = 300,
      cardHeight = 400,
      rotationAxis = "y",
      rotationDirection = "clockwise",
      rotationSpeed = 36, // ~36 degrees per second (10s per full rotation)
      initialRotation = 0,
      rotationOffset = 0,
      autoRotate = true,
      pauseOnHover = true,
      draggable = true,
      scrollRotate = false,
      snap = true,
      perspective = 1200,
      depth = 0,
      height,
      visibleArc = 360,
      cameraDistance = 0,
      activeScale = 1.1,
      activeOpacity = 1.0,
      activeBrightness = 1.0,
      sideScale = 0.8,
      sideOpacity = 0.6,
      sideBrightness = 0.7,
      backScale = 0.6,
      backOpacity = 0.0, // Set to 0.0 by default to prevent clutter in the middle background
      backBrightness = 0.4,
      hideBackCards = true, // Hide back cards by default to keep the center empty and focus on foreground
      shadowIntensity = 0.5,
      depthBlur = true,
      blurStrength = 4,
      reflection = false,
      ringTiltX = 15, // 15 degree pitch tilt for isometric view
      ringTiltY = 0,
      faceCamera = false, // Set to false to skew/narrow cards at the sides for high-end 3D feel
      tiltX = 0,
      tiltY = 0,
      tiltZ = 0,
      getCardTransform,
      renderCard,
      background = "transparent",
      className,
    },
    ref
  ) => {
    const containerRef = useRef<HTMLDivElement>(null);
    const [viewportWidth, setViewportWidth] = useState(
      typeof window !== "undefined" ? window.innerWidth : 1200
    );

    // Track resizing to prevent horizontal cutting on smaller screens
    useEffect(() => {
      const handleResize = () => {
        setViewportWidth(window.innerWidth);
      };
      window.addEventListener("resize", handleResize);
      return () => window.removeEventListener("resize", handleResize);
    }, []);

    const { cardAngles, angularSpacing, adjustedRadius } = useCylinder(
      cards.length,
      radius,
      cardWidth,
      gap,
      visibleArc
    );

    const rotationState = useRotation({
      angularSpacing,
      radius: adjustedRadius,
      rotationAxis,
      rotationDirection,
      rotationSpeed,
      initialRotation,
      autoRotate,
      pauseOnHover,
      snap,
    });

    useCardsTwoRef({
      ref,
      targetAngle: rotationState.targetAngle,
      angularSpacing,
      cardCount: cards.length,
      setIsPlaying: rotationState.setIsPlaying,
      getSnappedAngle: rotationState.getSnappedAngle,
    });

    // Keyboard navigation
    const handleKeyDown = (e: React.KeyboardEvent) => {
      if (angularSpacing === 0) return;
      if (e.key === "ArrowRight" || e.key === "ArrowDown") {
        e.preventDefault();
        rotationState.targetAngle.set(rotationState.targetAngle.get() - angularSpacing);
      } else if (e.key === "ArrowLeft" || e.key === "ArrowUp") {
        e.preventDefault();
        rotationState.targetAngle.set(rotationState.targetAngle.get() + angularSpacing);
      } else if (e.key === "Home") {
        e.preventDefault();
        rotationState.targetAngle.set(0);
      } else if (e.key === "End") {
        rotationState.targetAngle.set(-(cards.length - 1) * angularSpacing);
      }
    };

    // Wheel listener for scroll rotation
    useEffect(() => {
      if (!scrollRotate) return;
      const el = containerRef.current;
      if (!el) return;

      const handleWheel = (e: WheelEvent) => {
        e.preventDefault();
        const delta = e.deltaY * 0.001;
        rotationState.targetAngle.set(rotationState.targetAngle.get() - delta);
      };

      el.addEventListener("wheel", handleWheel, { passive: false });
      return () => el.removeEventListener("wheel", handleWheel);
    }, [scrollRotate, rotationState.targetAngle]);

    // Calculate maximum vertical displacement due to isometric tilt to set container height dynamically
    // This prevents vertical cutting/clipping
    const tiltRad = (Math.abs(ringTiltX) * Math.PI) / 180;
    const maxVerticalDrift = adjustedRadius * Math.sin(tiltRad) * 2;
    const computedHeight =
      height || Math.max(cardHeight * 1.5, maxVerticalDrift + cardHeight + 120);

    // Calculate dynamic scale factor to prevent horizontal screen overflow
    const maxDiameterNeeded = adjustedRadius * 2 + cardWidth + 80;
    const responsiveScale = Math.min(1, viewportWidth / maxDiameterNeeded);

    return (
      <div
        ref={containerRef}
        tabIndex={0}
        onKeyDown={handleKeyDown}
        onMouseEnter={() => {
          rotationState.isHoveredRef.current = true;
        }}
        onMouseLeave={() => {
          rotationState.isHoveredRef.current = false;
        }}
        className={cn(
          "relative flex items-center justify-center overflow-visible w-full select-none outline-none focus-visible:ring-2 focus-visible:ring-neutral-700 rounded-2xl",
          background === "solid" && "bg-neutral-950",
          background === "gradient" && "bg-gradient-to-b from-neutral-900 via-neutral-950 to-neutral-900",
          className
        )}
        style={{
          perspective: `${perspective}px`,
          height: typeof computedHeight === "number" ? `${computedHeight}px` : computedHeight,
        }}
      >
        {/* Decorative Grid Overlays */}
        {background === "grid" && (
          <div className="absolute inset-0 bg-[linear-gradient(to_right,#ffffff05_1px,transparent_1px),linear-gradient(to_bottom,#ffffff05_1px,transparent_1px)] bg-[size:24px_24px] [mask-image:radial-gradient(ellipse_60%_50%_at_50%_50%,#000_60%,transparent_100%)] pointer-events-none" />
        )}
        {background === "noise" && (
          <div className="absolute inset-0 opacity-[0.02] pointer-events-none" style={{ backgroundImage: "url(\"data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.85' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)'/%3E%3C/svg%3E\")" }} />
        )}

        {/* 3D Orbit Stage */}
        <motion.div
          className="relative flex items-center justify-center cursor-grab active:cursor-grabbing"
          onPanStart={draggable ? () => rotationState.handleDragStart() : undefined}
          onPan={draggable ? (_, info) => rotationState.handleDrag(info) : undefined}
          onPanEnd={draggable ? (_, info) => rotationState.handleDragEnd(info) : undefined}
          style={{
            transformStyle: "preserve-3d",
            // Apply both camera distance and responsive scaling factor
            transform: `translateZ(${cameraDistance}px) scale(${responsiveScale})`,
          }}
        >
          {cards.map((card, idx) => {
            const handleCardClick = () => {
              if (rotationState.isDragging) return;
              rotationState.targetAngle.set(-idx * angularSpacing);
            };

            return (
              <CardItem
                key={card.id}
                card={card}
                index={idx}
                cardAngle={cardAngles[idx] + (rotationOffset * Math.PI) / 180}
                cardWidth={cardWidth}
                cardHeight={cardHeight}
                radius={adjustedRadius}
                depth={depth}
                rotationAxis={rotationAxis}
                faceCamera={faceCamera}
                activeScale={activeScale}
                activeOpacity={activeOpacity}
                activeBrightness={activeBrightness}
                sideScale={sideScale}
                sideOpacity={sideOpacity}
                sideBrightness={sideBrightness}
                backScale={backScale}
                backOpacity={backOpacity}
                backBrightness={backBrightness}
                hideBackCards={hideBackCards}
                depthBlur={depthBlur}
                blurStrength={blurStrength}
                shadowIntensity={shadowIntensity}
                reflection={reflection}
                ringTiltX={ringTiltX}
                ringTiltY={ringTiltY}
                tiltX={tiltX}
                tiltY={tiltY}
                tiltZ={tiltZ}
                angularSpacing={angularSpacing}
                currentAngle={rotationState.currentAngle}
                getCardTransform={getCardTransform}
                renderCard={renderCard}
                onClick={handleCardClick}
              />
            );
          })}
        </motion.div>
      </div>
    );
  }
);

CardsTwo.displayName = "CardsTwo";

// Isolated Card Item Component to prevent parent re-renders and enable clean MotionValue calculations
interface CardItemProps {
  card: Card;
  index: number;
  cardAngle: number;
  cardWidth: number;
  cardHeight: number;
  radius: number;
  depth: number;
  rotationAxis: "x" | "y" | "z";
  faceCamera: boolean;
  activeScale: number;
  activeOpacity: number;
  activeBrightness: number;
  sideScale: number;
  sideOpacity: number;
  sideBrightness: number;
  backScale: number;
  backOpacity: number;
  backBrightness: number;
  hideBackCards: boolean;
  depthBlur: boolean;
  blurStrength: number;
  shadowIntensity: number;
  reflection: boolean;
  ringTiltX: number;
  ringTiltY: number;
  tiltX: number;
  tiltY: number;
  tiltZ: number;
  angularSpacing: number;
  currentAngle: any;
  getCardTransform: any;
  renderCard: any;
  onClick: () => void;
}

const CardItem = ({
  card,
  index,
  cardAngle,
  cardWidth,
  cardHeight,
  radius,
  depth,
  rotationAxis,
  faceCamera,
  activeScale,
  activeOpacity,
  activeBrightness,
  sideScale,
  sideOpacity,
  sideBrightness,
  backScale,
  backOpacity,
  backBrightness,
  hideBackCards,
  depthBlur,
  blurStrength,
  shadowIntensity,
  reflection,
  ringTiltX,
  ringTiltY,
  tiltX,
  tiltY,
  tiltZ,
  angularSpacing,
  currentAngle,
  getCardTransform,
  renderCard,
  onClick,
}: CardItemProps) => {
  const styles = useCardTransforms({
    index,
    cardAngle,
    currentAngle,
    radius,
    depth,
    rotationAxis,
    faceCamera,
    activeScale,
    activeOpacity,
    activeBrightness,
    sideScale,
    sideOpacity,
    sideBrightness,
    backScale,
    backOpacity,
    backBrightness,
    hideBackCards,
    depthBlur,
    blurStrength,
    tiltX,
    tiltY,
    tiltZ,
    ringTiltX,
    ringTiltY,
    angularSpacing,
    getCardTransform,
  });

  return (
    <motion.div
      onClick={onClick}
      className="absolute"
      style={{
        width: `${cardWidth}px`,
        height: `${cardHeight}px`,
        transform: useTransform(styles, (s) => s.transform),
        zIndex: useTransform(styles, (s) => s.zIndex),
        opacity: useTransform(styles, (s) => s.opacity),
        filter: useTransform(styles, (s) => s.filter),
        transformStyle: "preserve-3d",
        willChange: "transform, opacity, filter",
      }}
    >
      {/* Premium Floating Shadow */}
      <div
        className="absolute inset-0 rounded-2xl pointer-events-none transition-shadow duration-300"
        style={{
          boxShadow: `0 30px 60px -12px rgba(0, 0, 0, ${shadowIntensity * 0.75})`,
        }}
      />

      {/* Main Card Body */}
      <div className="w-full h-full rounded-2xl overflow-hidden border border-neutral-800/40 bg-neutral-900/90 text-neutral-200">
        {renderCard ? (
          renderCard(card, false)
        ) : (
          <div
            className={cn(
              "relative flex flex-col justify-end w-full h-full p-6 bg-cover bg-center select-none"
            )}
            style={{
              backgroundImage: card.image ? `url(${card.image})` : undefined,
              backgroundColor: !card.image ? "#171717" : undefined,
            }}
          >
            {/* Accent Background Layer */}
            {!card.image && card.background && (
              <div className={cn("absolute inset-0 opacity-40 bg-gradient-to-tr", card.background)} />
            )}

            {/* Badge */}
            {card.badge && (
              <span className="absolute top-4 right-4 px-2.5 py-1 text-[10px] font-semibold tracking-wider uppercase border border-neutral-700 bg-neutral-950/80 text-neutral-300 rounded-full z-20">
                {card.badge}
              </span>
            )}

            {/* Contents */}
            <div className="space-y-1.5 z-10 relative">
              {card.icon && <div className="text-white w-6 h-6 mb-2">{card.icon}</div>}
              <h3 className="text-xl font-bold tracking-tight text-white">{card.title}</h3>
              {card.subtitle && <p className="text-xs font-semibold text-neutral-400">{card.subtitle}</p>}
              {card.description && <p className="text-xs text-neutral-500 line-clamp-2 mt-1.5">{card.description}</p>}
            </div>

            {/* Ambient Dark/Vignette Overlay */}
            <div className="absolute inset-0 bg-gradient-to-t from-neutral-950 via-neutral-950/40 to-transparent z-0 pointer-events-none" />
          </div>
        )}
      </div>

      {/* Card Reflection */}
      {reflection && (
        <div
          className="absolute left-0 w-full rounded-2xl overflow-hidden border border-neutral-800/20 bg-neutral-900/40 opacity-[0.18] pointer-events-none origin-bottom select-none"
          style={{
            height: `${cardHeight}px`,
            bottom: `-${cardHeight + 8}px`,
            transform: "scaleY(-1)",
            WebkitMaskImage: "linear-gradient(to bottom, rgba(0,0,0,0) 45%, rgba(0,0,0,0.18))",
            maskImage: "linear-gradient(to bottom, rgba(0,0,0,0) 45%, rgba(0,0,0,0.18))",
          }}
        >
          {renderCard ? (
            renderCard(card, false)
          ) : (
            <div
              className="relative flex flex-col justify-end w-full h-full p-6 bg-cover bg-center"
              style={{
                backgroundImage: card.image ? `url(${card.image})` : undefined,
                backgroundColor: !card.image ? "#171717" : undefined,
              }}
            >
              {!card.image && card.background && (
                <div className={cn("absolute inset-0 opacity-40 bg-gradient-to-tr", card.background)} />
              )}
              <div className="absolute inset-0 bg-gradient-to-t from-neutral-950 via-neutral-950/40 to-transparent" />
            </div>
          )}
        </div>
      )}
    </motion.div>
  );
};

import { ReactNode } from "react";

export interface Card {
  id: string | number;
  title: string;
  subtitle?: string;
  description?: string;
  image?: string;
  background?: string;
  href?: string;
  content?: ReactNode;
  badge?: string;
  icon?: ReactNode;
}

export interface CardsTwoProps {
  cards: Card[];
  radius?: number; // default: 500
  gap?: number; // default: 20 (px spacing between cards)
  cardWidth?: number; // default: 300
  cardHeight?: number; // default: 400

  // Rotation system
  rotationAxis?: "x" | "y" | "z"; // default: "y"
  rotationDirection?: "clockwise" | "counter-clockwise"; // default: "counter-clockwise"
  rotationSpeed?: number; // auto-rotate speed in degrees per second. default: 5
  initialRotation?: number; // default: 0
  rotationOffset?: number; // default: 0

  // Interactions
  autoRotate?: boolean; // default: false
  pauseOnHover?: boolean; // default: true
  draggable?: boolean; // default: true
  scrollRotate?: boolean; // default: false
  snap?: boolean; // default: true

  // 3D parameters
  perspective?: number; // default: 1200
  depth?: number; // default: 0
  height?: number; // height override (useful for vertical rotation)
  visibleArc?: number; // visible arc in degrees (e.g. 180, 270, 360). default: 360
  cameraDistance?: number; // camera offset along Z axis. default: 0
  cameraFov?: number; // default: 60

  // Focusing & styling
  activeScale?: number; // default: 1.1
  activeOpacity?: number; // default: 1.0
  activeBrightness?: number; // default: 1.0

  sideScale?: number; // default: 0.8
  sideOpacity?: number; // default: 0.6
  sideBrightness?: number; // default: 0.7

  backScale?: number; // default: 0.6
  backOpacity?: number; // default: 0.2
  backBrightness?: number; // default: 0.4
  hideBackCards?: boolean; // default: false
  shadowIntensity?: number; // default: 0.5
  depthBlur?: boolean; // default: false
  blurStrength?: number; // default: 8
  reflection?: boolean; // default: false

  // Ring perspective tilts
  ringTiltX?: number; // default: 15 (isometric tilted ring)
  ringTiltY?: number; // default: 0

  // Individual Card tilts
  faceCamera?: boolean; // default: false
  tiltX?: number; // default: 0
  tiltY?: number; // default: 0
  tiltZ?: number; // default: 0

  // Callbacks
  getCardTransform?: (
    index: number,
    progress: number
  ) => {
    rotateX?: number;
    rotateY?: number;
    rotateZ?: number;
    scale?: number;
    opacity?: number;
    blur?: number;
    brightness?: number;
    translateX?: number;
    translateY?: number;
    translateZ?: number;
  };
  renderCard?: (card: Card, isActive: boolean) => ReactNode;
  background?: "solid" | "gradient" | "transparent" | "noise" | "grid"; // default: "transparent"
  className?: string;
}

export interface CardsTwoRef {
  next: () => void;
  previous: () => void;
  rotateTo: (index: number) => void;
  rotateBy: (angleDegrees: number) => void;
  reset: () => void;
  pause: () => void;
  play: () => void;
  getActiveIndex: () => number;
}

import { useMemo } from "react";

export function useCylinder(
  cardCount: number,
  radius: number,
  cardWidth: number,
  gap: number,
  visibleArcDegrees: number
) {
  return useMemo(() => {
    const visibleArcRadians = (visibleArcDegrees * Math.PI) / 180;

    // Auto-calculate the ideal radius required to prevent card overlaps
    // Circumference C = N * (W_card + gap) -> R = C / 2PI
    const circumferenceNeeded = cardCount * (cardWidth + gap);
    const idealRadius = circumferenceNeeded / (2 * Math.PI);

    // Use the larger of the user-requested radius or the ideal radius to guarantee no overlaps
    const adjustedRadius = visibleArcDegrees === 360
      ? Math.max(radius, idealRadius)
      : radius;

    let angularSpacing = 0;
    const cardAngles: number[] = [];

    if (visibleArcDegrees === 360) {
      // Symmetrical distribution around the full circle
      angularSpacing = (2 * Math.PI) / cardCount;
      for (let i = 0; i < cardCount; i++) {
        cardAngles.push(i * angularSpacing);
      }
    } else {
      // Spread cards evenly across the partial arc
      angularSpacing = cardCount > 1 ? visibleArcRadians / (cardCount - 1) : 0;
      const startAngle = -visibleArcRadians / 2;

      for (let i = 0; i < cardCount; i++) {
        cardAngles.push(startAngle + i * angularSpacing);
      }
    }

    return { cardAngles, angularSpacing, adjustedRadius };
  }, [cardCount, radius, cardWidth, gap, visibleArcDegrees]);
}

import { useRef, useState } from "react";
import { useMotionValue, useSpring, useAnimationFrame, PanInfo } from "framer-motion";

interface UseRotationParams {
  angularSpacing: number;
  radius: number;
  rotationAxis: "x" | "y" | "z";
  rotationDirection: "clockwise" | "counter-clockwise";
  rotationSpeed: number; // degrees per second
  initialRotation: number; // degrees
  autoRotate: boolean;
  pauseOnHover: boolean;
  snap: boolean;
}

export function useRotation({
  angularSpacing,
  radius,
  rotationAxis,
  rotationDirection,
  rotationSpeed,
  initialRotation,
  autoRotate,
  pauseOnHover,
  snap,
}: UseRotationParams) {
  const initialAngleRad = (initialRotation * Math.PI) / 180;
  const targetAngle = useMotionValue(initialAngleRad);

  // Spring configuration for physically heavy and smooth feeling
  const currentAngle = useSpring(targetAngle, {
    stiffness: 90,
    damping: 20,
    mass: 1.2,
    restDelta: 0.0001,
  });

  const [isDragging, setIsDragging] = useState(false);
  const [isPlaying, setIsPlaying] = useState(autoRotate);
  const isHoveredRef = useRef(false);

  const speedDirection = rotationDirection === "clockwise" ? 1 : -1;
  const speedRadPerSec = (rotationSpeed * Math.PI) / 180;

  // Auto-rotation loop
  useAnimationFrame((_, delta) => {
    if (!isPlaying) return;
    if (pauseOnHover && isHoveredRef.current) return;
    if (isDragging) return;

    const deltaSec = delta / 1000;
    const currentVal = targetAngle.get();
    targetAngle.set(currentVal + speedRadPerSec * speedDirection * deltaSec);
  });

  // Snap calculation helper
  const getSnappedAngle = (angle: number) => {
    if (angularSpacing === 0) return 0;
    const rawIndex = -angle / angularSpacing;
    const snappedIndex = Math.round(rawIndex);
    return -snappedIndex * angularSpacing;
  };

  // Drag handlers
  const dragStartRef = useRef(0);
  const handleDragStart = () => {
    setIsDragging(true);
    dragStartRef.current = targetAngle.get();
  };

  const handleDrag = (info: PanInfo) => {
    let deltaPx = 0;
    if (rotationAxis === "y") {
      deltaPx = info.offset.x;
    } else if (rotationAxis === "x") {
      deltaPx = -info.offset.y;
    } else {
      deltaPx = info.offset.x; // default fallback for Z-axis
    }

    // Map screen displacement to angular displacement
    const deltaAngle = deltaPx / radius;
    targetAngle.set(dragStartRef.current + deltaAngle);
  };

  const handleDragEnd = (info: PanInfo) => {
    setIsDragging(false);

    let velocityPx = 0;
    if (rotationAxis === "y") {
      velocityPx = info.velocity.x;
    } else if (rotationAxis === "x") {
      velocityPx = -info.velocity.y;
    } else {
      velocityPx = info.velocity.x;
    }

    const angularVelocity = velocityPx / radius;

    // Projected angle after inertia/momentum decays
    const decayFactor = 0.18; // Seconds of momentum slide
    const projectedAngle = targetAngle.get() + angularVelocity * decayFactor;

    if (snap) {
      const snappedAngle = getSnappedAngle(projectedAngle);
      targetAngle.set(snappedAngle);
    } else {
      targetAngle.set(projectedAngle);
    }
  };

  return {
    targetAngle,
    currentAngle,
    isDragging,
    isPlaying,
    setIsPlaying,
    isHoveredRef,
    handleDragStart,
    handleDrag,
    handleDragEnd,
    getSnappedAngle,
  };
}

import { useTransform, MotionValue } from "framer-motion";

interface UseCardTransformsParams {
  index: number;
  cardAngle: number;
  currentAngle: MotionValue<number>;
  radius: number;
  depth: number;
  rotationAxis: "x" | "y" | "z";
  faceCamera: boolean;
  activeScale: number;
  activeOpacity: number;
  activeBrightness: number;
  sideScale: number;
  sideOpacity: number;
  sideBrightness: number;
  backScale: number;
  backOpacity: number;
  backBrightness: number;
  hideBackCards: boolean;
  depthBlur: boolean;
  blurStrength: number;
  tiltX: number;
  tiltY: number;
  tiltZ: number;
  ringTiltX: number;
  ringTiltY: number;
  angularSpacing: number;
  getCardTransform?: (
    index: number,
    progress: number
  ) => {
    rotateX?: number;
    rotateY?: number;
    rotateZ?: number;
    scale?: number;
    opacity?: number;
    blur?: number;
    brightness?: number;
    translateX?: number;
    translateY?: number;
    translateZ?: number;
  };
}

export function useCardTransforms({
  index,
  cardAngle,
  currentAngle,
  radius,
  depth,
  rotationAxis,
  faceCamera,
  activeScale,
  activeOpacity,
  activeBrightness,
  sideScale,
  sideOpacity,
  sideBrightness,
  backScale,
  backOpacity,
  backBrightness,
  hideBackCards,
  depthBlur,
  blurStrength,
  tiltX,
  tiltY,
  tiltZ,
  ringTiltX,
  ringTiltY,
  angularSpacing,
  getCardTransform,
}: UseCardTransformsParams) {
  return useTransform(currentAngle, (ang) => {
    // Relative angle of the card from the front (radians)
    const alpha = cardAngle + ang;

    // Normalize angle to [-PI, PI] to handle continuous wrapping
    let relativeAngle = alpha % (2 * Math.PI);
    if (relativeAngle > Math.PI) relativeAngle -= 2 * Math.PI;
    if (relativeAngle < -Math.PI) relativeAngle += 2 * Math.PI;

    // Progress is the number of card steps offset from the center front
    const progress = angularSpacing > 0 ? relativeAngle / angularSpacing : 0;
    const cosVal = Math.cos(relativeAngle); // 1 at front, 0 at sides, -1 at back

    // 1. Coordinates Calculation
    let x0 = 0;
    let y0 = 0;
    let z0 = radius * cosVal;

    if (rotationAxis === "y") {
      x0 = radius * Math.sin(relativeAngle);
    } else if (rotationAxis === "x") {
      y0 = radius * Math.sin(relativeAngle);
    } else if (rotationAxis === "z") {
      x0 = radius * Math.sin(relativeAngle);
      y0 = radius * Math.cos(relativeAngle);
      z0 = 0;
    }

    // Apply X-axis ring tilt (pitch)
    const cosX = Math.cos((ringTiltX * Math.PI) / 180);
    const sinX = Math.sin((ringTiltX * Math.PI) / 180);
    const x1 = x0;
    const y1 = y0 * cosX - z0 * sinX;
    const z1 = y0 * sinX + z0 * cosX;

    // Apply Y-axis ring tilt (yaw)
    const cosY = Math.cos((ringTiltY * Math.PI) / 180);
    const sinY = Math.sin((ringTiltY * Math.PI) / 180);
    const x2 = x1 * cosY + z1 * sinY;
    const y2 = y1;
    const z2 = -x1 * sinY + z1 * cosY;

    // Output translation coordinates relative to center front (Z = 0 is front)
    let x = x2;
    let y = y2;
    let z = z2 - radius - depth;

    // 2. Base rotations
    let rotX = tiltX;
    let rotY = tiltY;
    let rotZ = tiltZ;

    if (!faceCamera) {
      const angleDegrees = -(relativeAngle * 180) / Math.PI;
      if (rotationAxis === "y") {
        rotY += angleDegrees;
        rotX += ringTiltX; // Align pitch tilt with the ring
      } else if (rotationAxis === "x") {
        rotX += angleDegrees;
        rotY += ringTiltY;
      } else if (rotationAxis === "z") {
        rotZ += angleDegrees;
      }
    }

    // 3. Piecewise scale, opacity, and brightness calculations
    // frontFactor goes from 1 (front) to 0 (back)
    const frontFactor = (1 + cosVal) / 2;

    let scale = sideScale;
    let opacity = sideOpacity;
    let brightness = sideBrightness;

    if (cosVal >= 0) {
      // Front half: interpolate between side (at 0) and active (at 1)
      scale = sideScale + (activeScale - sideScale) * cosVal;
      opacity = sideOpacity + (activeOpacity - sideOpacity) * cosVal;
      brightness = sideBrightness + (activeBrightness - sideBrightness) * cosVal;
    } else {
      // Back half: interpolate between back (at -1) and side (at 0)
      // (1 + cosVal) goes from 0 (at -1) to 1 (at 0)
      const t = 1 + cosVal;
      scale = backScale + (sideScale - backScale) * t;
      opacity = backOpacity + (sideOpacity - backOpacity) * t;
      brightness = backBrightness + (sideBrightness - backBrightness) * t;
    }

    let blurVal = 0;

    // Back card visibility check
    if (cosVal < 0) {
      if (hideBackCards) {
        opacity = 0;
      }
    }

    // Depth Blur
    if (depthBlur) {
      blurVal = (1 - frontFactor) * blurStrength;
    }

    // 4. Custom developer transforms hook (override engine)
    if (getCardTransform) {
      const custom = getCardTransform(index, progress);
      if (custom.rotateX !== undefined) rotX = custom.rotateX;
      if (custom.rotateY !== undefined) rotY = custom.rotateY;
      if (custom.rotateZ !== undefined) rotZ = custom.rotateZ;
      if (custom.scale !== undefined) scale = custom.scale;
      if (custom.opacity !== undefined) opacity = custom.opacity;
      if (custom.blur !== undefined) blurVal = custom.blur;
      if (custom.brightness !== undefined) brightness = custom.brightness;
      if (custom.translateX !== undefined) x = custom.translateX;
      if (custom.translateY !== undefined) y = custom.translateY;
      if (custom.translateZ !== undefined) z = custom.translateZ;
    }

    // Dynamic Z-Index Mapping
    const zIndex = Math.round(z + 10000);

    // Build transform string
    const transform = `translate3d(${x}px, ${y}px, ${z}px) rotateX(${rotX}deg) rotateY(${rotY}deg) rotateZ(${rotZ}deg) scale(${scale})`;

    const filter = [
      blurVal > 0.1 ? `blur(${blurVal.toFixed(1)}px)` : "",
      brightness !== 1 ? `brightness(${brightness.toFixed(2)})` : "",
    ]
      .filter(Boolean)
      .join(" ");

    return {
      transform,
      zIndex,
      opacity,
      filter: filter || "none",
    };
  });
}

import { Ref, useImperativeHandle } from "react";
import { MotionValue } from "framer-motion";
import { CardsTwoRef } from "../types";

interface UseCardsTwoRefParams {
  ref: Ref<CardsTwoRef> | undefined;
  targetAngle: MotionValue<number>;
  angularSpacing: number;
  cardCount: number;
  setIsPlaying: (playing: boolean) => void;
  getSnappedAngle: (angle: number) => number;
}

export function useCardsTwoRef({
  ref,
  targetAngle,
  angularSpacing,
  cardCount,
  setIsPlaying,
  getSnappedAngle,
}: UseCardsTwoRefParams) {
  useImperativeHandle(ref, () => ({
    next: () => {
      const current = targetAngle.get();
      // Snap to nearest index first before decrementing to avoid cumulative offset errors
      const snapped = getSnappedAngle(current);
      targetAngle.set(snapped - angularSpacing);
    },
    previous: () => {
      const current = targetAngle.get();
      // Snap to nearest index first before incrementing to avoid cumulative offset errors
      const snapped = getSnappedAngle(current);
      targetAngle.set(snapped + angularSpacing);
    },
    rotateTo: (index: number) => {
      const boundedIndex = Math.max(0, Math.min(cardCount - 1, index));
      targetAngle.set(-boundedIndex * angularSpacing);
    },
    rotateBy: (angleDegrees: number) => {
      const angleRad = (angleDegrees * Math.PI) / 180;
      targetAngle.set(targetAngle.get() + angleRad);
    },
    reset: () => {
      targetAngle.set(0);
    },
    pause: () => {
      setIsPlaying(false);
    },
    play: () => {
      setIsPlaying(true);
    },
    getActiveIndex: () => {
      const current = targetAngle.get();
      if (angularSpacing === 0) return 0;
      const rawIndex = -current / angularSpacing;
      return Math.max(0, Math.min(cardCount - 1, Math.round(rawIndex)));
    },
  }));
}
